SELECT [Sales Header].[Customer Order Ref_] AS RiferimentoOrdineCliente, [Sales Line].Reference AS ReferenzaOrdineCliente, [Sales Header].[Delete Reason], [Sales Line].Type, [Sales Line].[Document No_] AS OrdineNr, [Sales Line].[Line No_] AS LineaNr, Val([quantity]) AS quantita, [Sales Line].No_ AS articolo, [Sales Line].[Description 2] AS Descrizione2, [Variable Code].[Variable Code] AS Colore, [Variable Code].Description AS DescrizioneColore, Val([no_ of pairs]) AS paia, [Sales Line].[Assortment Code] AS Assortimento
FROM ([Sales Header] INNER JOIN [Sales Line] ON ([Sales Header].No_ = [Sales Line].[Document No_]) AND ([Sales Header].[Document Type] = [Sales Line].[Document Type])) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code]) AND ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]);

